mapper.insert:
INSERT INTO PLANNER ( PLANNER_ID
                    , WS_ID
                    , TITLE
                    , PARTICIPANTS
                    , COLOR
                    , CAL_YEAR
                    , CAL_MONTH
                    , ITINERARY
                    , REGIST_DT
                    , REGIST_ID
                    , UPDT_DT
                    , UPDT_ID)
VALUES ( #{plannerId,    jdbcType=VARCHAR}
       , #{wsId,         jdbcType=VARCHAR}
       , #{title,        jdbcType=VARCHAR}
       , #{participants, typeHandler=com.terry.backend.thirdparty.handlers.ListStringTypeHandler}
       , #{color,        jdbcType=VARCHAR}
       , #{calYear,      jdbcType=INTEGER}
       , #{calMonth,     jdbcType=INTEGER}
       , #{itinerary,    typeHandler=com.terry.backend.thirdparty.handlers.PlannerItineraryTypeHandler}
       , NOW()
       , #{registId,     jdbcType=VARCHAR}
       , NOW()
       , #{registId,     jdbcType=VARCHAR})

mapper.update:
UPDATE PLANNER
SET ITINERARY = #{itinerary, typeHandler=com.terry.backend.thirdparty.handlers.PlannerItineraryTypeHandler}
  , UPDT_DT   = NOW()
  , UPDT_ID   = #{updtId, jdbcType=VARCHAR}
WHERE PLANNER_ID = #{plannerId, jdbcType=VARCHAR}

mapper.select:
SELECT COUNT(*) > 0
FROM WORKSPACE_USER
WHERE WS_ID   = #{workspaceId, jdbcType=VARCHAR}
  AND USER_ID = #{userId,      jdbcType=VARCHAR}
